3	import (
4		"fmt"
5		"strings"
6	)
7	
8	// RefOnlyEntry is one ref the agent should resolve via its own tools
9	// (the ref-only metadata strategy in FEAT-022 §2). Path and Title are
10	// emitted; content is intentionally not inlined.
11	type RefOnlyEntry struct {
12		Path  string
13		Title string
14	}
15	
16	// AssembleRefOnly emits a metadata-only listing of refs. Suitable when
17	// the agent has filesystem access and the prompt does not need to
18	// guarantee the agent saw specific content (FEAT-022 §2).
19	func AssembleRefOnly(entries []RefOnlyEntry) string {
20		if len(entries) == 0 {
21			return ""
22		}
23		var b strings.Builder
24		for _, e := range entries {
25			if e.Title != "" {
26				fmt.Fprintf(&b, "- %s — %s\n", e.Path, e.Title)
27			} else {
28				fmt.Fprintf(&b, "- %s\n", e.Path)
29			}
30		}
31		return b.String()
32	}
33	
34	// InlineAssembly is the result of AssembleInline.
35	type InlineAssembly struct {
36		Prompt   string
37		Sections []EvidenceAssemblySection
38		// Overflow is true when, after all trimming, the assembled prompt
39		// would still exceed total. Callers (reviewer/grader) MUST NOT
40		// dispatch when Overflow is true (FEAT-022 §7) and should emit the
41		// appropriate context_overflow outcome class instead.
42		Overflow bool
43	}
44	
45	// AssembleInline assembles a prompt by joining priority-ordered
46	// sections under a total byte budget (FEAT-022 §2 inline-with-cap
47	// strategy). Per-section caps and floor semantics are honored via the
48	// SectionInput fields. Sections are joined verbatim with a single
49	// newline separator between non-empty bodies.
50	func AssembleInline(sections []SectionInput, total int) InlineAssembly {
51		fit := FitSections(sections, total)
52	
53		var b strings.Builder
54		for i, s := range fit.Included {
55			if i > 0 {
56				b.WriteByte('\n')
57			}
58			b.WriteString(s.Content)
59		}
60		out := b.String()
61	
62		overflow := len(out) > total
63		return InlineAssembly{
64			Prompt:   out,
65			Sections: fit.Sections,
66			Overflow: overflow,
67		}
68	}
