16	// beadReviewFixture returns the deterministic inputs used by both the
17	// golden-file generator and the collapse-equivalence test.
18	func beadReviewFixture(t *testing.T) (*bead.Bead, []agent.GoverningRef, string, string, string) {
19		t.Helper()
20		root, err := filepath.Abs(filepath.Join("testdata", "bead_review"))
21		if err != nil {
22			t.Fatalf("abs testdata path: %v", err)
23		}
24		b := &bead.Bead{
25			ID:    "ddx-fixture",
26			Title: `fixture <title> with "quotes" & 'apos'`,
27			Description: "Line one with <tag> & \"quoted\" 'apos'\n" +
28				"Line two has > and < and & sentinels.",
29			Acceptance: "AC#1: <required> & \"satisfied\"\n" +
30				"AC#2: 'covered' > baseline",
31			Labels: []string{"kind:refactor", `area:<agent>&"x"`},
32		}
33		refs := []agent.GoverningRef{
34			{ID: "FEAT-XX", Path: "governing.md", Title: `Sample <Doc> & "Title"`},
35		}
36		rev := "deadbee"
37		diff := "commit deadbee\nAuthor: Test <test@example.com>\n\n" +
38			"diff --git a/x.go b/x.go\n" +
39			"+ added line with <tag> & \"q\" 'a'\n"
40		return b, refs, rev, diff, root
41	}
