93	// TestBeadReviewCommandWiring confirms the post-collapse CLI handler
94	// (`ddx bead review <id>`) routes prompt assembly through
95	// agent.BuildReviewPrompt: it invokes the cobra command end-to-end against
96	// a real git commit and a real bead store, and asserts the output carries
97	// the same XML structure that BuildReviewPrompt emits for the same inputs.
98	func TestBeadReviewCommandWiring(t *testing.T) {
99		if _, err := exec.LookPath("git"); err != nil {
100			t.Skip("git not available")
101		}
102	
103		tmp := t.TempDir()
104		runGit := func(args ...string) {
105			t.Helper()
106			c := exec.Command("git", args...)
107			c.Dir = tmp
108			c.Env = append(os.Environ(),
109				"GIT_AUTHOR_NAME=Test", "GIT_AUTHOR_EMAIL=test@example.com",
110				"GIT_COMMITTER_NAME=Test", "GIT_COMMITTER_EMAIL=test@example.com",
111			)
112			if out, err := c.CombinedOutput(); err != nil {
113				t.Fatalf("git %s: %v: %s", strings.Join(args, " "), err, out)
114			}
115		}
116		runGit("init", "-q")
117		runGit("config", "user.email", "test@example.com")
118		runGit("config", "user.name", "Test")
119		if err := os.WriteFile(filepath.Join(tmp, "x.go"), []byte("package x\n"), 0o644); err != nil {
120			t.Fatal(err)
121		}
122		runGit("add", "x.go")
123		runGit("commit", "-q", "-m", "init")
124		c := exec.Command("git", "rev-parse", "HEAD")
125		c.Dir = tmp
126		shaOut, err := c.Output()
127		if err != nil {
128			t.Fatalf("rev-parse: %v", err)
129		}
130		sha := strings.TrimSpace(string(shaOut))
131	
132		ddxDir := filepath.Join(tmp, ".ddx")
133		if err := os.MkdirAll(ddxDir, 0o755); err != nil {
134			t.Fatal(err)
135		}
136		store := bead.NewStore(ddxDir)
137		if err := store.Init(); err != nil {
138			t.Fatalf("store init: %v", err)
139		}
140		b := &bead.Bead{
141			ID:          "ddx-wire",
142			Title:       `wired <title> & "x"`,
143			Description: "desc <a> & 'b'",
144			Acceptance:  "AC#1 <ok>",
145			Extra:       map[string]any{"closing_commit_sha": sha},
146		}
147		if err := store.Create(b); err != nil {
148			t.Fatalf("store create: %v", err)
149		}
150		// Persist closing_commit_sha through Update so it round-trips via Extra.
151		if err := store.Update("ddx-wire", func(bd *bead.Bead) {
152			if bd.Extra == nil {
153				bd.Extra = map[string]any{}
154			}
155			bd.Extra["closing_commit_sha"] = sha
156		}); err != nil {
157			t.Fatalf("update: %v", err)
158		}
159	
160		factory := NewCommandFactory(tmp)
